  parameter VFMV_F_S        =   5'b00000;
  parameter VFMV_S_F        =   5'b00000;  // vs2 field

  `ifdef ZVFBFWMA_ON
  // OPF* instructions
  parameter VFWMACCBF16     =   6'b111_011; 

  // vfunary0. They can be distinguished by vs1 field(inst_encoding[19:15]).
  parameter VFNCVTBF16      =   5'b11101;
  parameter VFWCVTBF16      =   5'b01101;
  `endif
`endif

// parameter for lsu decoding
  parameter  UNIT_STRIDE       = 3'b000;
  parameter  UNORDERED_INDEX   = 3'b001;
  parameter  CONSTANT_STRIDE   = 3'b010;
  parameter  ORDERED_INDEX     = 3'b011;

  parameter  US_REGULAR        = 5'b00000;
  parameter  US_WHOLE_REGISTER = 5'b01000;
  parameter  US_MASK           = 5'b01011;
  parameter  US_FAULT_FIRST    = 5'b10000;

// Number of REG
  parameter NREG1 = 3'b000;  
  parameter NREG2 = 3'b001;
  parameter NREG4 = 3'b011;
  parameter NREG8 = 3'b111;

// Number of FIELD
  parameter NF1 = 3'b000;  
  parameter NF2 = 3'b001;
  parameter NF3 = 3'b010;
  parameter NF4 = 3'b011;
  parameter NF5 = 3'b100;
  parameter NF6 = 3'b101;
  parameter NF7 = 3'b110;
  parameter NF8 = 3'b111;

`endif // HDL_VERILOG_RVV_OPCODE_SVH

content.content:
1	// description:
2	// 1. Dispatch unit receives uop instructions from uop queue
3	// 2. Dispatch unit check rules to determine if the uops are sent to reservation stations(RS). 
4	//    There are two ways to solve: 
5	//     a. stall pipeline
6	//     b. foreward data from ROB
7	// 3. Dispatch unit read vector data from VRF for uops.
8	
9	`ifndef HDL_VERILOG_RVV_DESIGN_RVV_SVH
10	`include "rvv_backend.svh"
11	`endif
12	`ifndef RVV_DISPATCH__SVH
13	`include "rvv_backend_dispatch.svh"
14	`endif
15	
16	module rvv_backend_dispatch
17	(
18	    clk,
19	    rst_n,
20	    uop_valid_uop2dp,
21	    uop_uop2dp,
22	    uop_ready_dp2uop,
23	    rs_valid_dp2alu,
24	    rs_dp2alu,
25	    rs_ready_alu2dp,
26	    rs_valid_dp2pmtrdt,
27	    rs_dp2pmtrdt,
28	    rs_ready_pmtrdt2dp,
29	    rs_valid_dp2mul,
30	    rs_dp2mul,
31	    rs_ready_mul2dp,
32	    rs_valid_dp2div,
33	    rs_dp2div,
34	    rs_ready_div2dp,
35	`ifdef ZVE32F_ON
36	    rs_valid_dp2falu,
37	    rs_dp2falu,
38	    rs_ready_falu2dp,
39	`endif
40	    rs_valid_dp2lsu,
41	    rs_dp2lsu,
42	    rs_ready_lsu2dp,
43	    mapinfo_valid_dp2lsu,
44	    mapinfo_dp2lsu,
45	    mapinfo_ready_lsu2dp,
46	    uop_valid_dp2rob,
47	    uop_dp2rob,
48	    uop_ready_rob2dp,
49	    rob_entry_rob2dp,
50	    rd_index_dp2vrf,        
51	    rd_data_vrf2dp,
52	    v0_mask_vrf2dp,
53	    rob_entry
54	);  
55	// ---port definition-------------------------------------------------
56	// global signal
57	    input  logic           clk;
58	    input  logic           rst_n;
59	
60	// Uops Queue to Dispatch unit
61	    input  logic        [`NUM_DP_UOP-1:0]         uop_valid_uop2dp;
62	    input  UOP_QUEUE_t  [`NUM_DP_UOP-1:0]         uop_uop2dp;
63	    output logic        [`NUM_DP_UOP-1:0]         uop_ready_dp2uop;
64	
65	// Dispatch unit sends oprations to reservation stations
66	// Dispatch unit to ALU reservation station
67	// rs_*: reservation station
68	    output logic          [`NUM_DP_UOP-1:0]       rs_valid_dp2alu;
69	    output ALU_RS_t       [`NUM_DP_UOP-1:0]       rs_dp2alu;
70	    input  logic          [`NUM_DP_UOP-1:0]       rs_ready_alu2dp;
71	
72	// Dispatch unit to PMT+RDT reservation station
73	    output logic          [`NUM_DP_UOP-1:0]       rs_valid_dp2pmtrdt;
74	    output PMT_RDT_RS_t   [`NUM_DP_UOP-1:0]       rs_dp2pmtrdt;
75	    input  logic          [`NUM_DP_UOP-1:0]       rs_ready_pmtrdt2dp;
76	
77	// Dispatch unit to MUL reservation station
78	    output logic          [`NUM_DP_UOP-1:0]       rs_valid_dp2mul;
79	    output MUL_RS_t       [`NUM_DP_UOP-1:0]       rs_dp2mul;
80	    input  logic          [`NUM_DP_UOP-1:0]       rs_ready_mul2dp;
81	
82	// Dispatch unit to DIV reservation station
83	    output logic          [`NUM_DP_UOP-1:0]       rs_valid_dp2div;
84	    output DIV_RS_t       [`NUM_DP_UOP-1:0]       rs_dp2div;
85	    input  logic          [`NUM_DP_UOP-1:0]       rs_ready_div2dp;
86	
87	`ifdef ZVE32F_ON
88	// Dispatch unit to FMA reservation station
89	    output logic          [`NUM_DP_UOP-1:0]       rs_valid_dp2falu;
90	    output FMA_RS_t       [`NUM_DP_UOP-1:0]       rs_dp2falu;
91	    input  logic          [`NUM_DP_UOP-1:0]       rs_ready_falu2dp;
92	`endif
93	
94	// Dispatch unit to LSU 
95	    // to LSU RS
96	    output logic          [`NUM_DP_UOP-1:0]       rs_valid_dp2lsu;
97	    output UOP_RVV2LSU_t  [`NUM_DP_UOP-1:0]       rs_dp2lsu;
98	    input  logic          [`NUM_DP_UOP-1:0]       rs_ready_lsu2dp;
99	    // to LSU MAP INFO
100	    output logic          [`NUM_DP_UOP-1:0]       mapinfo_valid_dp2lsu;
101	    output LSU_MAP_INFO_t [`NUM_DP_UOP-1:0]       mapinfo_dp2lsu;
102	    input  logic          [`NUM_DP_UOP-1:0]       mapinfo_ready_lsu2dp;
103	
104	// Dispatch unit pushes operations to ROB unit    
105	    output logic          [`NUM_DP_UOP-1:0]       uop_valid_dp2rob;
106	    output DP2ROB_t       [`NUM_DP_UOP-1:0]       uop_dp2rob;
107	    input  logic          [`NUM_DP_UOP-1:0]       uop_ready_rob2dp;
108	    input  logic          [`ROB_DEPTH_WIDTH-1:0]  rob_entry_rob2dp;
109	
110	// Dispatch unit sends read request to VRF for vector data.
111	// Dispatch unit to VRF unit
112	// rd_data would be return from VRF at the current cycle.
113	    output logic [`NUM_DP_VRF-1:0][`REGFILE_INDEX_WIDTH-1:0] rd_index_dp2vrf;          
114	    input  logic [`NUM_DP_VRF-1:0][`VLEN-1:0]                rd_data_vrf2dp;
115	    input  logic [`VLEN-1:0]                                 v0_mask_vrf2dp;
116	
117	// Dispatch unit accept all ROB entry to determine if vs_data of RS is from ROB or not
118	// ROB unit to Dispatch unit
119	    input  ROB2DP_t     [`ROB_DEPTH-1:0]          rob_entry;
120	
121	// ---internal signal definition--------------------------------------
122	    SUC_UOP_RAW_t       [`NUM_DP_UOP-1:0]   suc_uop;
123	    PRE_UOP_RAW_t       [`ROB_DEPTH-1:0]    pre_uop_rob;
124	    PRE_UOP_RAW_t       [`NUM_DP_UOP-2:0]   pre_uop_uop;
125	    RAW_UOP_ROB_t       [`NUM_DP_UOP-1:0]   raw_uop_rob; 
126	    // uop0 is the first uop so no need raw check between uops for it
127	    RAW_UOP_UOP_t       [`NUM_DP_UOP-1:1]   raw_uop_uop; 
128	
129	    STRCT_UOP_t         [`NUM_DP_UOP-1:0]   strct_uop;
130	    ARCH_HAZARD_t                           arch_hazard;
131	
132	    UOP_OPN_t           [`NUM_DP_UOP-1:0]   uop_operand;
133	    UOP_OPN_t           [`NUM_DP_UOP-1:0]   vrf_byp;
134	    ROB_BYP_t           [`ROB_DEPTH-1:0]    rob_byp;
135	
136	    UOP_CTRL_t          [`NUM_DP_UOP-1:0]   uop_ctrl;
137	
138	    UOP_INFO_t          [`NUM_DP_UOP-1:0]   uop_info;
139	    UOP_OPN_BYTE_TYPE_t [`NUM_DP_UOP-1:0]   uop_operand_byte_type;
140	
141	    logic [`NUM_DP_UOP-1:0][`VL_WIDTH-1:0]          vlmax;
142	    logic [`NUM_DP_UOP-1:0][$clog2(`VL_WIDTH)-1:0]  vlmax_shift;
143	
144	    logic [`NUM_DP_UOP-1:0][`ROB_DEPTH_WIDTH-1:0]   rob_address;
145	
146	// ---code start------------------------------------------------------
147	    genvar i;
148	
149	    // vlmax = lmul * `VLENB / sew 
150	    generate
151	      for (i=0; i<`NUM_DP_UOP; i++) begin : gen_vlmax
152	        assign vlmax_shift[i] = ($clog2(`VL_WIDTH))'(uop_uop2dp[i].vector_csr.lmul[1:0]) 
153	                                + $clog2(`VLENB) 
154	                                - ($clog2(`VL_WIDTH))'(uop_uop2dp[i].vector_csr.sew) 
155	                                - {{($clog2(`VL_WIDTH)-3){1'b0}},uop_uop2dp[i].vector_csr.lmul[2],2'b0};
156	        assign vlmax[i] = (`VL_WIDTH)'(1) << vlmax_shift[i];
157	      end
158	    endgenerate
159	
160	    generate
161	        for (i=0; i<`NUM_DP_UOP; i++) begin : gen_suc_uop
162	            assign suc_uop[i].vs1_index = uop_uop2dp[i].vs1;
163	            assign suc_uop[i].vs1_valid = uop_uop2dp[i].vs1_valid;
164	            assign suc_uop[i].vs2_index = uop_uop2dp[i].vs2_index;
165	            assign suc_uop[i].vs2_valid = uop_uop2dp[i].vs2_valid;
166	            assign suc_uop[i].vd_index  = uop_uop2dp[i].dst_index;
167	            assign suc_uop[i].vs3_valid = uop_uop2dp[i].vs3_valid;
168	            assign suc_uop[i].vm        = uop_uop2dp[i].vm;
169	        end
170	    endgenerate
171	// RAW data hazard check between uop[*] and ROB
172	    generate
173	        for (i=0; i<`ROB_DEPTH; i++) begin : gen_pre_uop_rob
174	            assign pre_uop_rob[i].w_index = rob_entry[i].w_index;
175	            assign pre_uop_rob[i].w_type  = rob_entry[i].w_type;
176	            assign pre_uop_rob[i].w_valid = rob_entry[i].w_valid;
177	            assign pre_uop_rob[i].valid   = rob_entry[i].valid;
178	        end
179	        for (i=0; i<`NUM_DP_UOP; i++) begin : gen_raw_uop_rob
180	            rvv_backend_dispatch_raw_uop_rob #(
181	            ) u_raw_uop_rob (
182	                .raw_uop_rob  (raw_uop_rob[i]),
183	                .suc_uop      (suc_uop[i]),
184	                .pre_uop      (pre_uop_rob)
185	            );
186	        end
187	    endgenerate
188	
189	// RAW data hazard check between uop(s)
190	    generate
191	        for (i=0; i<`NUM_DP_UOP-1; i++) begin : gen_pre_uop_uop
192	            assign pre_uop_uop[i].w_index = uop_uop2dp[i].dst_index;
193	            assign pre_uop_uop[i].w_valid = 1'b0;
194	            assign pre_uop_uop[i].w_type  = uop_uop2dp[i].vd_valid ? VRF : XRF;
195	            assign pre_uop_uop[i].valid   = uop_uop2dp[i].vd_valid & uop_valid_uop2dp[i];
196	        end
197	        for (i=1; i<`NUM_DP_UOP; i++) begin : gen_raw_uop_uop
198	            rvv_backend_dispatch_raw_uop_uop #(
199	                .PREUOP_NUM (i)
200	            ) u_raw_uop_uop (
201	                .raw_uop_uop  (raw_uop_uop[i]),
202	                .suc_uop      (suc_uop[i]),
203	                .pre_uop      (pre_uop_uop[i-1:0])
204	            );
205	        end
206	    endgenerate
207	
208	// Structure hazard check and set read index for VRF
209	    generate
210	        for (i=0; i<`NUM_DP_UOP; i++) begin : gen_strct_uop
211	            assign strct_uop[i].vs1_index = uop_uop2dp[i].vs1;
212	            assign strct_uop[i].vs1_valid = uop_uop2dp[i].vs1_valid;
213	            assign strct_uop[i].vs2_index = uop_uop2dp[i].vs2_index;
214	            assign strct_uop[i].vs2_valid = uop_uop2dp[i].vs2_valid;
215	            assign strct_uop[i].vd_index  = uop_uop2dp[i].dst_index;
216	            assign strct_uop[i].vs3_valid = uop_uop2dp[i].vs3_valid;
217	            assign strct_uop[i].uop_exe_unit = uop_uop2dp[i].uop_exe_unit;
218	            assign strct_uop[i].uop_class = uop_uop2dp[i].uop_class;
219	        end
220	    endgenerate
221	
222	    rvv_backend_dispatch_structure_hazard #(
223	    ) u_structure_hazard (
224	        .rd_index     (rd_index_dp2vrf),
225	        .arch_hazard  (arch_hazard),
226	        .strct_uop    (strct_uop)
227	    );
228	
229	// Bypass data for source operand of uop(s)
230	    generate
231	      for (i=0; i<`ROB_DEPTH; i++) begin : gen_rob_byp
232	        assign rob_byp[i].w_data    = rob_entry[i].w_data;
233	        assign rob_byp[i].byte_type = rob_entry[i].byte_type;
234	
235	        `ifdef AGNOSTIC_ONE
236	          assign rob_byp[i].tail_one  = rob_entry[i].vector_csr.vtype.vta;
237	          assign rob_byp[i].inactive_one = rob_entry[i].vector_csr.vtype.vma;
238	        `else
239	          assign rob_byp[i].tail_one  = 1'b0;
240	          assign rob_byp[i].inactive_one = 1'b0;
241	        `endif
242	      end
243	
244	      rvv_backend_dispatch_operand
245	      u_operand
246	      (
247	        .vrf_byp        (vrf_byp       ),
248	        .uop_uop2dp     (uop_uop2dp    ),
249	        .rd_data_vrf2dp (rd_data_vrf2dp),
250	        .v0_mask_vrf2dp (v0_mask_vrf2dp)
251	      );
252	
253	      for (i=0;i<`NUM_DP_UOP;i++) begin: gen_bypass_data
254	        rvv_backend_dispatch_bypass 
255	        #(
256	        ) 
257	        u_bypass (
258	          .uop_operand  (uop_operand[i]),
259	          .rob_byp      (rob_byp),
260	          .vrf_byp      (vrf_byp[i]),
261	          .raw_uop_rob  (raw_uop_rob[i])
262	        );
263	      end
264	    endgenerate
265	
266	// Control handshae mechanism for uop_queue <-> dispath, dispatch <-> rs and dispatch <-> rob
267	    generate
268	        for (i=0; i<`NUM_DP_UOP; i++) begin : gen_uop_ctrl
269	            assign uop_ctrl[i].uop_exe_unit = uop_uop2dp[i].uop_exe_unit;
270	            assign uop_ctrl[i].pshrob_valid = uop_uop2dp[i].pshrob_valid;
271	            assign uop_ctrl[i].pshlsu_valid = uop_uop2dp[i].pshlsu_valid;
272	        end
273	    endgenerate
274	
275	    rvv_backend_dispatch_ctrl #(
276	    ) u_ctrl (
277	      // ctrl input signal
278	        .raw_uop_rob            (raw_uop_rob),
279	        .raw_uop_uop            (raw_uop_uop),
280	        .arch_hazard            (arch_hazard),
281	        .uop_ctrl               (uop_ctrl),
282	      // handshake signals
283	        .uop_valid_uop2dp       (uop_valid_uop2dp),
284	        .uop_ready_dp2uop       (uop_ready_dp2uop),
285	        .rs_valid_dp2alu        (rs_valid_dp2alu),
286	        .rs_ready_alu2dp        (rs_ready_alu2dp),
287	        .rs_valid_dp2pmtrdt     (rs_valid_dp2pmtrdt),
288	        .rs_ready_pmtrdt2dp     (rs_ready_pmtrdt2dp),
289	        .rs_valid_dp2mul        (rs_valid_dp2mul),
290	        .rs_ready_mul2dp        (rs_ready_mul2dp),
291	        .rs_valid_dp2div        (rs_valid_dp2div),
292	        .rs_ready_div2dp        (rs_ready_div2dp),
293	      `ifdef ZVE32F_ON
294	        .rs_valid_dp2falu        (rs_valid_dp2falu),
295	        .rs_ready_falu2dp        (rs_ready_falu2dp),
296	      `endif
297	        .rs_valid_dp2lsu        (rs_valid_dp2lsu),
298	        .rs_ready_lsu2dp        (rs_ready_lsu2dp),
299	        .mapinfo_valid_dp2lsu   (mapinfo_valid_dp2lsu),
300	        .mapinfo_ready_lsu2dp   (mapinfo_ready_lsu2dp),
301	        .uop_valid_dp2rob       (uop_valid_dp2rob),
302	        .uop_ready_rob2dp       (uop_ready_rob2dp)
303	    );
304	
305	// determine the type for each byte in uop's vector operands 
306	    generate
307	        for (i=0; i<`NUM_DP_UOP; i++) begin : gen_opr_bype_type
308	            assign uop_info[i].uop_index  = (uop_uop2dp[i].uop_exe_unit==LSU)&(uop_uop2dp[i].uop_funct6.lsu_funct6.lsu_is_seg==IS_SEGMENT)? 
309	                                            uop_uop2dp[i].seg_field_index : uop_uop2dp[i].uop_index[$clog2(`EMUL_MAX)-1:0];
310	            assign uop_info[i].uop_exe_unit = uop_uop2dp[i].uop_exe_unit;
311	            assign uop_info[i].vd_eew     = uop_uop2dp[i].vd_eew;
312	            assign uop_info[i].vs1_eew    = uop_uop2dp[i].vs1_eew;
313	            assign uop_info[i].vs2_eew    = uop_uop2dp[i].vs2_eew;
314	            assign uop_info[i].vstart     = uop_uop2dp[i].vector_csr.vstart;
315	            assign uop_info[i].vl         = uop_uop2dp[i].vs_evl;
316	            assign uop_info[i].vm         = uop_uop2dp[i].vm;
317	            assign uop_info[i].ignore_vma = uop_uop2dp[i].ignore_vma;
318	            assign uop_info[i].ignore_vta = uop_uop2dp[i].ignore_vta;
319	
320	            rvv_backend_dispatch_opr_byte_type #(
321	            ) u_opr_byte_type (
322	                .operand_byte_type (uop_operand_byte_type[i]),
323	                .uop_info          (uop_info[i]),
324	                .v0_data           (uop_operand[i].v0)
325	            );
326	        end
327	    endgenerate
328	
329	// output signals for RS+ROB
330	    generate
331	        for (i=0; i<`NUM_DP_UOP; i++) begin : gen_output_sig
332	          // rob_address
333	            if (i==0) begin : gen_rob_address_0
334	              assign rob_address[0] = rob_entry_rob2dp;
335	            end else begin : gen_rob_address_i
336	              assign rob_address[i] = rob_address[i-1] + (`ROB_DEPTH_WIDTH)'(uop_uop2dp[i-1].pshrob_valid);
337	            end
338	
339	          // ALU RS
340	          `ifdef TB_SUPPORT
341	            assign rs_dp2alu[i].uop_pc          = uop_uop2dp[i].uop_pc; 
342	          `endif
343	            assign rs_dp2alu[i].rob_entry       = rob_address[i]; 
344	            assign rs_dp2alu[i].uop_funct6      = uop_uop2dp[i].uop_funct6;
345	            assign rs_dp2alu[i].uop_funct3      = uop_uop2dp[i].uop_funct3;
346	            assign rs_dp2alu[i].is_cmp          = uop_uop2dp[i].uop_exe_unit==CMP; 
347	            assign rs_dp2alu[i].vstart          = uop_uop2dp[i].vector_csr.vstart;
348	            assign rs_dp2alu[i].vl              = uop_uop2dp[i].vs_evl;
349	            assign rs_dp2alu[i].vm              = uop_uop2dp[i].vm;
350	            assign rs_dp2alu[i].vxrm            = uop_uop2dp[i].vector_csr.xrm;
351	            assign rs_dp2alu[i].v0_data         = uop_operand[i].v0;
352	            assign rs_dp2alu[i].v0_data_valid   = uop_uop2dp[i].v0_valid;
353	            assign rs_dp2alu[i].vd_data         = uop_operand[i].vd;
354	            assign rs_dp2alu[i].vd_data_valid   = uop_uop2dp[i].vs3_valid;
355	            assign rs_dp2alu[i].vd_eew          = uop_uop2dp[i].vd_eew;
356	            assign rs_dp2alu[i].vs1             = uop_uop2dp[i].vs1;
357	            assign rs_dp2alu[i].vs1_data        = uop_uop2dp[i].vs1_valid ? uop_operand[i].vs1 : (`VLEN)'(uop_uop2dp[i].rs1_data);
358	            assign rs_dp2alu[i].vs1_data_valid  = uop_uop2dp[i].vs1_valid;
359	            assign rs_dp2alu[i].rs1_data_valid  = uop_uop2dp[i].rs1_data_valid;
360	            assign rs_dp2alu[i].vs2_data        = uop_operand[i].vs2;
361	            assign rs_dp2alu[i].vs2_data_valid  = uop_uop2dp[i].vs2_valid;
362	            assign rs_dp2alu[i].vs2_eew         = uop_uop2dp[i].vs2_eew;
363	            assign rs_dp2alu[i].first_uop_valid = uop_uop2dp[i].first_uop_valid;
364	            assign rs_dp2alu[i].last_uop_valid  = uop_uop2dp[i].last_uop_valid;
365	            assign rs_dp2alu[i].uop_index       = uop_uop2dp[i].uop_index[$clog2(`EMUL_MAX)-1:0];
366	
367	          // PMTRDT RS
368	          `ifdef TB_SUPPORT
369	            assign rs_dp2pmtrdt[i].uop_pc          = uop_uop2dp[i].uop_pc; 
370	          `endif
371	            assign rs_dp2pmtrdt[i].rob_entry       = rob_address[i]; 
372	            assign rs_dp2pmtrdt[i].uop_exe_unit    = uop_uop2dp[i].uop_exe_unit; 
373	            assign rs_dp2pmtrdt[i].uop_funct6      = uop_uop2dp[i].uop_funct6;
374	            assign rs_dp2pmtrdt[i].uop_funct3      = uop_uop2dp[i].uop_funct3;
375	            assign rs_dp2pmtrdt[i].vl              = uop_uop2dp[i].vs_evl;
376	            assign rs_dp2pmtrdt[i].vm              = uop_uop2dp[i].vm;
377	            assign rs_dp2pmtrdt[i].vlmax           = vlmax[i];
378	            assign rs_dp2pmtrdt[i].v0_data         = uop_operand[i].v0;
379	            assign rs_dp2pmtrdt[i].vs1_data        = uop_operand[i].vs1;
380	            assign rs_dp2pmtrdt[i].vs1_eew         = uop_uop2dp[i].vs1_eew;
381	            assign rs_dp2pmtrdt[i].vs1_data_valid  = uop_uop2dp[i].vs1_valid;
382	            assign rs_dp2pmtrdt[i].vs2_index       = uop_uop2dp[i].vs2_index;
383	            assign rs_dp2pmtrdt[i].vs2_data        = uop_operand[i].vs2;
384	            assign rs_dp2pmtrdt[i].vs2_eew         = uop_uop2dp[i].vs2_eew;
385	            assign rs_dp2pmtrdt[i].vs2_type        = uop_operand_byte_type[i].vs2;
386	            assign rs_dp2pmtrdt[i].vd_eew          = uop_uop2dp[i].vd_eew;
387	            assign rs_dp2pmtrdt[i].dst_index       = uop_uop2dp[i].dst_index;
388	            assign rs_dp2pmtrdt[i].rs1_data        = uop_uop2dp[i].rs1_data;
389	            assign rs_dp2pmtrdt[i].first_uop_valid = uop_uop2dp[i].first_uop_valid;
390	            assign rs_dp2pmtrdt[i].last_uop_valid  = uop_uop2dp[i].last_uop_valid;
391	            assign rs_dp2pmtrdt[i].uop_index       = uop_uop2dp[i].uop_index[$clog2(`EMUL_MAX)-1:0];
392	          `ifdef ZVE32F_ON
393	            assign rs_dp2pmtrdt[i].frm             = uop_uop2dp[i].vector_csr.frm;
394	          `endif
395	            
396	          // MUL/MAC RS
397	          `ifdef TB_SUPPORT
398	            assign rs_dp2mul[i].uop_pc          = uop_uop2dp[i].uop_pc; 
399	          `endif
400	            assign rs_dp2mul[i].rob_entry       = rob_address[i]; 
401	            assign rs_dp2mul[i].uop_funct6      = uop_uop2dp[i].uop_funct6;
402	            assign rs_dp2mul[i].uop_funct3      = uop_uop2dp[i].uop_funct3;
403	            assign rs_dp2mul[i].vxrm            = uop_uop2dp[i].vector_csr.xrm;
404	            assign rs_dp2mul[i].vs1_data        = uop_uop2dp[i].vs1_valid ? uop_operand[i].vs1 : (`VLEN)'(uop_uop2dp[i].rs1_data);
405	            assign rs_dp2mul[i].vs1_data_valid  = uop_uop2dp[i].vs1_valid;
406	            assign rs_dp2mul[i].rs1_data_valid  = uop_uop2dp[i].rs1_data_valid;
407	            assign rs_dp2mul[i].vs2_data        = uop_operand[i].vs2;
408	            assign rs_dp2mul[i].vs2_data_valid  = uop_uop2dp[i].vs2_valid;
409	            assign rs_dp2mul[i].vs2_eew         = uop_uop2dp[i].vs2_eew;
410	            assign rs_dp2mul[i].vs3_data        = uop_operand[i].vd;
411	            assign rs_dp2mul[i].vs3_data_valid  = uop_uop2dp[i].vs3_valid;
412	            assign rs_dp2mul[i].uop_index       = uop_uop2dp[i].uop_index[0];
413	
414	          // DIV RS
415	          `ifdef TB_SUPPORT
416	            assign rs_dp2div[i].uop_pc          = uop_uop2dp[i].uop_pc; 
417	          `endif
418	            assign rs_dp2div[i].rob_entry       = rob_address[i]; 
419	            assign rs_dp2div[i].uop_funct6      = uop_uop2dp[i].uop_funct6;
420	            assign rs_dp2div[i].uop_funct3      = uop_uop2dp[i].uop_funct3;
421	            assign rs_dp2div[i].is_div          = uop_uop2dp[i].uop_exe_unit==DIV; 
422	            assign rs_dp2div[i].vs1_data        = uop_uop2dp[i].vs1_valid ? uop_operand[i].vs1 : (`VLEN)'(uop_uop2dp[i].rs1_data);
423	            assign rs_dp2div[i].vs1_data_valid  = uop_uop2dp[i].vs1_valid;
424	            assign rs_dp2div[i].rs1_data_valid  = uop_uop2dp[i].rs1_data_valid;
425	            assign rs_dp2div[i].vs2_data        = uop_operand[i].vs2;
426	            assign rs_dp2div[i].vs2_eew         = uop_uop2dp[i].vs2_eew;
427	            assign rs_dp2div[i].vs2_data_valid  = uop_uop2dp[i].vs2_valid;
428	          `ifdef ZVE32F_ON
429	            assign rs_dp2div[i].frm             = uop_uop2dp[i].vector_csr.frm;
430	            assign rs_dp2div[i].vs1             = uop_uop2dp[i].vs1;
431	          `endif
432	
433	          `ifdef ZVE32F_ON
434	          // FMA RS
435	          `ifdef TB_SUPPORT
436	            assign rs_dp2falu[i].uop_pc          = uop_uop2dp[i].uop_pc; 
437	          `endif
438	            assign rs_dp2falu[i].rob_entry       = rob_address[i]; 
439	            assign rs_dp2falu[i].uop_funct6      = uop_uop2dp[i].uop_funct6;
440	            assign rs_dp2falu[i].uop_funct3      = uop_uop2dp[i].uop_funct3;
441	            assign rs_dp2falu[i].uop_exe_unit    = uop_uop2dp[i].uop_exe_unit;
442	            assign rs_dp2falu[i].vstart          = uop_uop2dp[i].vector_csr.vstart;
443	            assign rs_dp2falu[i].vl              = uop_uop2dp[i].vs_evl;
444	            assign rs_dp2falu[i].vm              = uop_uop2dp[i].vm;
445	            assign rs_dp2falu[i].frm             = uop_uop2dp[i].vector_csr.frm;
446	            assign rs_dp2falu[i].v0_data         = uop_operand[i].v0[`VLENW*`EMUL_MAX-1:0];
447	            assign rs_dp2falu[i].v0_data_valid   = uop_uop2dp[i].v0_valid;
448	            assign rs_dp2falu[i].vs1             = uop_uop2dp[i].vs1;
449	            assign rs_dp2falu[i].vs1_data        = uop_operand[i].vs1;
450	            assign rs_dp2falu[i].vs1_data_valid  = uop_uop2dp[i].vs1_valid;
451	            assign rs_dp2falu[i].vs2_data        = uop_operand[i].vs2;
452	            assign rs_dp2falu[i].vs2_data_valid  = uop_uop2dp[i].vs2_valid;
453	            assign rs_dp2falu[i].vs2_eew         = uop_uop2dp[i].vs2_eew;
454	            assign rs_dp2falu[i].vs3_data        = uop_operand[i].vd;
455	            assign rs_dp2falu[i].vs3_data_valid  = uop_uop2dp[i].vs3_valid;
456	            assign rs_dp2falu[i].rs1_data        = uop_uop2dp[i].rs1_data;
457	            assign rs_dp2falu[i].rs1_data_valid  = uop_uop2dp[i].rs1_data_valid;
458	            assign rs_dp2falu[i].last_uop_valid  = uop_uop2dp[i].last_uop_valid;
459	            assign rs_dp2falu[i].uop_index       = uop_uop2dp[i].uop_index[$clog2(`EMUL_MAX)-1:0];            
460	          `endif
461	
462	          // LSU RS
463	          `ifdef TB_SUPPORT
464	            assign rs_dp2lsu[i].uop_pc              = uop_uop2dp[i].uop_pc; 
465	          `endif
466	            assign rs_dp2lsu[i].vidx_valid          = uop_uop2dp[i].vs2_valid;
467	            assign rs_dp2lsu[i].vidx_addr           = uop_uop2dp[i].vs2_index;
468	            assign rs_dp2lsu[i].vidx_data           = uop_operand[i].vs2;
469	            assign rs_dp2lsu[i].vregfile_read_valid = uop_uop2dp[i].vs3_valid;
470	            assign rs_dp2lsu[i].vregfile_read_addr  = uop_uop2dp[i].dst_index;
471	            assign rs_dp2lsu[i].vregfile_read_data  = uop_operand[i].vd;
472	            assign rs_dp2lsu[i].v0_valid            = uop_uop2dp[i].v0_valid;
473	            assign rs_dp2lsu[i].v0_data             = uop_operand_byte_type[i].v0_strobe;
474	
475	          // LSU MAP INFO
476	          `ifdef TB_SUPPORT
477	            assign mapinfo_dp2lsu[i].uop_pc              = uop_uop2dp[i].uop_pc; 
478	          `endif
479	            assign mapinfo_dp2lsu[i].valid               = mapinfo_valid_dp2lsu[i];
480	            assign mapinfo_dp2lsu[i].rob_entry           = rob_address[i];
481	            assign mapinfo_dp2lsu[i].lsu_class           = uop_uop2dp[i].uop_funct6.lsu_funct6.lsu_is_store;
482	            assign mapinfo_dp2lsu[i].vregfile_write_addr = uop_uop2dp[i].dst_index;
483	
484	          // ROB
485	          `ifdef TB_SUPPORT
486	            assign uop_dp2rob[i].uop_pc         = uop_uop2dp[i].uop_pc; 
487	          `endif
488	            assign uop_dp2rob[i].w_index        = uop_uop2dp[i].dst_index;
489	            assign uop_dp2rob[i].w_type         = uop_uop2dp[i].vd_valid ? VRF : 
490	          `ifdef ZVE32F_ON
491	                                                  uop_uop2dp[i].fd_valid ? FRF :
492	          `endif
493	                                                  XRF;
494	            assign uop_dp2rob[i].byte_type      = uop_operand_byte_type[i].vd;
495	            assign uop_dp2rob[i].vector_csr     = uop_uop2dp[i].vector_csr;
496	            assign uop_dp2rob[i].last_uop_valid = uop_uop2dp[i].last_uop_valid;
497	        end
498	    endgenerate
499	
500	endmodule
